PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?type ?title ?premieremonth ?premiereyear WHERE {
  ?content a :Content .
  ?reviews a :Reviews .
  ?reviews p:hasContent ?content .
  ?content p:type ?type .
  ?content p:title ?title .
  ?content p:premiereMonth ?premieremonth .
  ?content p:premiereYear ?premiereyear .
  ?reviews p:rating ?rating_f .
  FILTER(?rating_f = 5)
} }
  component: { SELECT ?type ?title ?premiereyear WHERE {
  ?content a :Content .
  ?reviews a :Reviews .
  ?reviews p:hasContent ?content .
  ?content p:type ?type .
  ?content p:title ?title .
  ?content p:premiereYear ?premiereyear .
  ?reviews p:rating ?rating_f .
  FILTER(?rating_f = 5)
} }
  component_2: { SELECT ?type ?title ?premieremonth WHERE {
  ?content a :Content .
